<script>
document.addEventListener('DOMContentLoaded', () => {
    const optionsDataSource = document.getElementById('options-data');
    const container = document.getElementById('button-container');

    if (!optionsDataSource || !container) return;

    const optionsText = optionsDataSource.innerHTML;
    const lines = optionsText.trim().split('\n');

    container.innerHTML = ''; 

    lines.forEach(line => {
        const trimmedLine = line.trim();
        if (!trimmedLine) return;

        const match = trimmedLine.match(/^\s*\d+\.\s*(.*)$/);
        let actionText = trimmedLine; 

        if (match) {
            actionText = match[1].trim(); 
        }

        const button = document.createElement('button');
        button.className = 'action-btn-final'; 
        button.textContent = trimmedLine; 
        button.setAttribute('data-action', actionText); 

        button.addEventListener('click', (event) => {
            event.stopPropagation();
            let textToAppend = button.getAttribute('data-action');
            if (!textToAppend) return;

            textToAppend = textToAppend.replace(/\(.*?\)/g, '').trim();

            try {
                const input = window.parent.document.querySelector('#send_textarea');
                if (input) {
                    const currentValue = input.value.trim();
                    input.value = currentValue ? `${currentValue}\n${textToAppend}` : textToAppend;
                    input.dispatchEvent(new Event('input', { bubbles: true }));
                }
            } catch (error) { 
                console.error('SillyTavern Regex Error:', error); 
            }

            document.querySelectorAll('#button-container .action-btn-final').forEach(b => b.classList.remove('active'));
            button.classList.add('active');
        });

        container.appendChild(button);
    });
});

const detailsElement = document.querySelector('.card-final-version');
const toggleButton = document.querySelector('.toggle-collapse-btn');
if (detailsElement && toggleButton) {
  detailsElement.addEventListener('toggle', () => {
    toggleButton.textContent = detailsElement.open ? '收起' : '展开';
  });
}
</script>

</body>
</html>
