                    const inputArea = window.parent.document.querySelector('#send_textarea');
                    if (inputArea) {
                        const newText = inputArea.value.trim().length > 0 ? '\n' + text : text;
                        inputArea.value += (inputArea.value.trim().length > 0 ? '\n' : '') + text;
                        inputArea.dispatchEvent(new Event('input', { bubbles: true }));
                    }
                } catch (error) {
                    console.warn('SillyTavern UI 链接失败:', error);
                }
            };
            document.querySelectorAll('.antennae-action-btn').forEach(btn => {
                btn.addEventListener('click', function() {
                    const text = this.innerText.trim();
                    if(text) handleSend(text);
